var e=[{id:`L7_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_NULL`,text:{KOREA:`전원, 목표를 고치로 유인하라! 너무 가까이 갈 필요 없다!`,JPN:`全員、ターゲットを繭に誘導しろ！　あまり近づく必要はないぞ！`,ENG:`All units, lure the target to the cocoon! Be careful not to get too close!`,TWN:`全體隊員，用繭引誘目標，別太靠近！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT1`,slots:{L:{char_id:`GUARD_EXILER_NPC_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`GUARD_EXILER_NPC_NULL`,text:{KOREA:`천천히 물러나면서 튀어나오는 적들만 처리해!`,JPN:`ゆっくり後退しつつ、飛び出してくる敵のみを相手にしろ！`,ENG:`Fall back and only deal with the ones that pop out!`,TWN:`慢慢地退後，只處理視線範圍內的敵人！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT1`,slots:{L:null,C:null,R:{char_id:`GUARD_EXILER_NPC_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`JACOB_NPC_NULL_NULL`,text:{KOREA:`못 해먹겠네, 진짜!`,JPN:`ったく、やってられねえ！`,ENG:`You've got to be kidding me!`,TWN:`討厭，我受夠了！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT1`,slots:{L:null,C:{char_id:`JACOB_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`JACOB_NPC_NULL_NULL`,text:{KOREA:`젠장! 어쩌다 내가 이딴 미친 짓을!`,JPN:`クソ！　こんなイカれた作戦に何で俺が！`,ENG:`Dammit! How did I even end up here?!`,TWN:`該死！我怎麼會做出這種瘋狂的事！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT1`,slots:{L:null,C:{char_id:`JACOB_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_AP_NULL`,text:{KOREA:`어라? 어디 가세요, 제이콥 씨? 그 쪽은 위험하다고요?`,JPN:`あれ？　どこに行くんですか、ジェイコブさん？　そちらは危ないですよ？`,ENG:`Huh? Where do you think you're going, Jacob? That area's dangerous, you know.`,TWN:`咦？你要去哪裡，雅各？那邊很危險的喔～`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT1`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JACOB_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`JACOB_NPC_NULL_NULL`,text:{KOREA:`시끄러워. 이래봬도 난 제5방위선의 담당관이야!`,JPN:`うるさい。これでも俺は第5防衛線の担当官だ！`,ENG:`Shut it! I'm still in charge of the 5th Defense Line!`,TWN:`閉嘴，再怎麼說我也是第五防線的負責人！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT1`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JACOB_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`JACOB_NPC_NULL_NULL`,text:{KOREA:`네놈들 없이도, 내 살길은 내가 찾아!`,JPN:`あんたらなんかいなくても、俺は俺で何とかする！`,ENG:`I don't need your help! I'll find my own way out!!`,TWN:`不需要你們幫忙，我也能找到活路！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT1`,slots:{L:{char_id:`JOOSHIYOON_FENRIR_AP_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`JACOB_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`고치가! 아포리아가 고치에 도달했어!`,JPN:`繭が！　アポリアが繭に到達したわ！`,ENG:`The cocoon! Aporia's arrived near the cocoon!`,TWN:`注意！阿波利亞已經抵達繭的位置！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT1`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`전 대원, 전장으로부터 이탈합니다! 고치로부터 최대한 떨어지세요!`,JPN:`全隊員、戦場から離脱！　繭からできるだけ遠くに離れてください！`,ENG:`All units, retreat from the battlefield! Get as far away from the cocoon as possible!`,TWN:`全體隊員，撤離戰場！離繭越遠越好！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT1`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`목표는 전방의 아포리아 및 다수의 침식체 무리!`,JPN:`ターゲットは前方のアポリアおよび多数の侵食体の群れです！`,ENG:`Our objective is Aporia and the horde of C.O.s ahead of us!`,TWN:`目標為前方的阿波利亞及多個侵蝕體！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT1`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`KYLE_DELTA_AP_NULL`,text:{KOREA:`모든 사일로 오픈! 이터니움 반응탄, 서른두 발! 순차 사격 개시!!`,JPN:`すべてのサイロを開放！　エタニウム反応弾、32発！　順次射撃開始！！`,ENG:`Open all silos! 32 shots of Eternium-reactivated warheads! Fire!!`,TWN:`預備發射！永恆之金反應彈，32枚！開始依序發射！！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT1`,slots:{L:null,C:{char_id:`KYLE_DELTA_AP_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`LONE_EXILER_NPC_NULL`,text:{KOREA:`젠장, 맡겨 달라고!!`,JPN:`くそっ、任せておけ！！`,ENG:`Dammit, leave it to me!!`,TWN:`可惡，交給我吧！！`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT1`,slots:{L:null,C:{char_id:`LONE_EXILER_NPC_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L33_1`,type:`dialog`,speaker:`LONE_EXILER_NPC_NULL`,text:{KOREA:`소령, 어떻게 됐어? 아포리아는?`,JPN:`少佐、どうなった？　アポリアは？`,ENG:`Major, how did it go? And Aporia?`,TWN:`少校，怎麼樣了？阿波利亞呢？`},stage:{bg:`CITY_STREET_DISASTER_CORRUPT2`,slots:{L:null,C:{char_id:`LONE_EXILER_NPC_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};